_Next_Enforcement_Beast_Mode AS (
  SELECT `seller_id`, `enforcement_configuration_id`, `bp_brand_id`, `brand_assigned_user`, `brand_assigned_user_initials`, `storefront_enforceable`, `brand_enforceable`, `assigned_user_id`, `country_id`, `upc`, `vendor_code`, `catalog_map`, `Brand`, `Storefront ID`, `marketplace_channel_id`, `marketplace_channel`, `country`, `Last Notice Type`, `Last Notice Sent`, `Last Note`, `Invoice ID`, `Job ID`, `USPS Tracking`, `Delivery Status`, `Delivery Date`, `Enforcement History`, `C2M ERROR_STATUS`, `Recipient Address`, `Notes`, `sales_country_id`, `revenue`, `asins units`, `revenue brand`, `asins units brand`, `Percent Mix of Brand`, `Revenue Rank R3MTH`, `Revenue Distribution R3MTH`, `scraped_date`, `amazonID`, `sellerId`, `sellerName`, `storefront_name`, `asin`, `isQuantityRestricted`, `isFBA`, `upc_name`, `msrp`, `srp`, `map`, `parent_category`, `child_category`, `child_category_2`, `child_category_3`, `partner name`, `offer_price`, `offer_date_max_price`, `Units`, `Limit Buster Units`, `redirect_asin`, `created_date`, `created_time`, `sku_map`, `sku_name`, `buy_box_count`, `Partner - Brand`, `cod_condition`, `unit_in_listing`, `asin_bp_enforceable`, `BBC_ORIGINAL_STATUS`, `BBC_2_8_22_STATUS`, `id`, `Enter Date`, `New Notes`, `New Invoice ID`, (COALESCE(`Units` * `offer_price`,0)) AS `inventory_value`, ((`offer_price`-`map`)/`map`) AS `price_delta_map`, ((CASE when `Brand`= 'BioSil' AND `Last Notice Type` = 'Certified Mail' then 'Investigate' when `Brand` = 'Pure Planet' AND `Last Notice Type` = '2nd Email'  then 'Investigate' when `Brand` in ('Stokke','BABYZEN') AND `Last Notice Type` = 'Certified Mail'  then 'Investigate' when (`Brand` in ('All American 1930','de Buyer','dpHUE','BrainMD','FEKKAI', 'Masimo','Stork','Messermeister', 'PetAg', 'Scanpan', 'TenPoint','OOFOS','Terry Naturally','EuroMedica','Milk Makeup', 'Strider','NEST New York','North American Herb & Spice','Kneipp','Doona','Mission','Hydroxycut','Yogasleep','Bach') or `partner name` in ('Total Resources International')) AND `Last Notice Type` is NULL  then  CASE WHEN `country` = 'United States' THEN '1st Notice - Certified Mail' ELSE '1st Notice - USPS Mail' END when `Brand` in ('Stokke','BABYZEN') AND `Last Notice Type` = 'Initial Letter' then 'No Further Action' when `sellerId` = 'A12SR9CZCS7BA0' then 'Contentious' when `Last Notice Type` is null then '1st Notice - USPS Mail' when `Last Notice Type`='1st Email' then '1st Notice - USPS Mail' when `Last Notice Type`='2nd Email' then '1st Notice - USPS Mail' when `Last Notice Type`= '1st Notice - USPS Mail' then CASE WHEN `country` = 'United States' THEN '2nd Notice - Certified Mail' ELSE '2nd Notice - USPS Mail' END when `Last Notice Type`= '1st Notice - USPS Mail' AND `Delivery Status` LIKE '%delivered%' then 'Certified Mail' when `Last Notice Type`= '1st Notice - Certified Mail' AND `Delivery Status` LIKE '%delivered%' then CASE WHEN `country` = 'United States' THEN '2nd Notice - Certified Mail' ELSE '2nd Notice - USPS Mail' END when `Last Notice Type`IN ('Certified Mail','1st Notice - Certified Mail', '2nd Notice - Certified Mail', '2nd Certified Mail') AND `Delivery Status` LIKE '%delivered%' then 'Cease & Desist' when `Last Notice Type`IN ('1st Notice - Certified Mail') AND `Delivery Status` IN ('No Authorized Recipient Available','Addressee Unknown','Delivery Status Not Updated','Arrived at Recipient PO','Arrival at Unit','Return Noticed Generated','No Access','Dead Mail/Disposed by Post Office','Tendered to Agent for Final Delivery','Redelivery Scheduled ','Business Closed','Arrival at Pickup Point','2Nd Notice Generated','Notice Left','Pre-Shipment Info Sent to USPS','Return to Sender','Forwarded','Return to Sender Processing','No Secure Location Available','Unclaimed','Forward Expired','Insufficient Address','Dead Mail/Sent to Recovery Center','Missent') then 'Investigate / Resend' when `Last Notice Type`IN ('1st Notice - USPS Mail') AND `Delivery Status` IN ('No Authorized Recipient Available','Addressee Unknown','Delivery Status Not Updated','Arrived at Recipient PO','Arrival at Unit','Return Noticed Generated','No Access','Dead Mail/Disposed by Post Office','Tendered to Agent for Final Delivery','Redelivery Scheduled ','Business Closed','Arrival at Pickup Point','2Nd Notice Generated','Notice Left','Pre-Shipment Info Sent to USPS','Return to Sender','Forwarded','Return to Sender Processing','No Secure Location Available','Unclaimed','Forward Expired','Insufficient Address','Dead Mail/Sent to Recovery Center','Missent','Enroute/Processed') then 'Investigate / Resend 1st Notice - USPS Mail' when `Last Notice Type` IN ('1st Notice - Certified Mail','2nd Notice - Certified Mail', 'Certified Mail','1st Notice - USPS Mail') AND `Delivery Status` IN ('En Route','Shipment Acceptance','Printed','In Transit','RESCHEDULED TO NEXT DELIVERY DAY    ','Dispatched from Sort Facility ','Enroute/Processed','Out for Delivery','Dispatched from Sort Facility','AVAILABLE FOR REDLVRY OR PICKUP         ','Provided to postal processing facility','DLVRY EXCPT ANIMAL INTERFERENCE         ','','Provided to Postal Processing Facility','Tendered to Agent for Final Delivery') then 'Monitor' when `Last Notice Type`= 'USPS Mail'  then 'Monitor' when `Last Notice Type`= 'Certified Mail' AND (`Delivery Status`) IS NULL then 'Investigate' when `Last Notice Type`= 'USPS Mail' AND `C2M ERROR_STATUS` = 'FAILED' then 'Investigate' when `Last Notice Type` = 'Cease & Desist' then 'Investigate' when `Last Notice Type` = 'Misc Email' then 'Investigate' when `Last Notice Type`='1st Email' AND `Last Note` LIKE '%reply%' then '2nd Email Reply' when `storefront_name` = 'iHerb LLC' then 'Tell Brand' when `storefront_name` = 'OxKom' then 'Tell Brand' when `storefront_name` = 'Swanson Health Products' then 'Tell Brand' when `partner name` = 'Nutraceutical' then 'Misc. Email' else '' end)) AS `next_enforcement` FROM _Filter_Rows
),

_Group_By AS (
  SELECT `scraped_date`, `Brand`, `storefront_name`, `Last Notice Type`, `next_enforcement`, `assigned_user_id`, `brand_assigned_user`, `Last Notice Sent`, `sellerId`, `bp_brand_id`, `marketplace_channel`, `marketplace_channel_id`, `country_id`, `country`, SUM(`inventory_value`) AS `inventory_value`, AVG(`price_delta_map`) AS `price_deta_map`, COUNT(`asin`) AS `asin_count` FROM _Next_Enforcement_Beast_Mode GROUP BY `scraped_date`, `Brand`, `storefront_name`, `Last Notice Type`, `next_enforcement`, `assigned_user_id`, `brand_assigned_user`, `Last Notice Sent`, `sellerId`, `bp_brand_id`, `marketplace_channel`, `marketplace_channel_id`, `country_id`, `country`
),

_Select_Columns AS (
  SELECT `scraped_date`, `Brand` AS `brand`, `storefront_name`, `Last Notice Type` AS `last_notice_type`, `Last Notice Sent` AS `last_notice_sent`, `next_enforcement`, `assigned_user_id`, `brand_assigned_user`, `inventory_value`, `price_deta_map` AS `avg_map_variance`, `sellerId` AS `storefront_id`, `asin_count`, `bp_brand_id`, `marketplace_channel`, `marketplace_channel_id`, `country_id`, `country` FROM _Group_By
),

_Enforcement_Actions_DS AS (
  SELECT * FROM _Select_Columns
)

